  "lessonText": "Understanding note values is essential for playing melodies.",
  "data": {
    "cards": [
      {
        "front": "What is a whole note?",
        "back": "A whole note is held for four beats.",
        "icon": "🎵"
      },
      {
        "front": "What is a half note?",
        "back": "A half note is held for two beats.",
        "icon": "🎶"
      },
      {
        "front": "What is a quarter note?",
        "back": "A quarter note is held for one beat.",
        "icon": "🎼"
      },
      {
        "front": "What is an eighth note?",
        "back": "An eighth note is held for half a beat.",
        "icon": "🎤"
      }
    ]
  }
}
